CheckCheatManager = {}

function CheckCheatManager:onTick(ticks)
    if ticks % (5 * GameMatch.tickPerSecond) ~= 0 then
        return
    end

    for _, vPlayer in pairs(PlayerManager:getPlayers()) do
        if vPlayer.curArea == Define.Area.AutoArea then
            if not vPlayer.property:hasPayItem(Define.PayItemType.AutoWorkout)
                    and not vPlayer.property.advAutoWork then
                vPlayer:teleportPos(vPlayer:randomInitPos())
            end
            --LogUtil.log(string.format("CheckCheatManager:onTick %s %d %s",
            --        tostring(vPlayer.rakssid), vPlayer.property.payItemList[tostring(Define.PayItemType.AutoWorkout)],
            --        tostring(vPlayer.property.advAutoWork)))
        end
    end

    --LogUtil.log("CheckCheatManager:onTick " .. os.time())
end

return CheckCheatManager